import new_sentry_scope, {capturing} from "@/public/sentry";
import { Msg } from '@/public/msg'
import Tab = chrome.tabs.Tab;
import MessageSender = chrome.runtime.MessageSender;
import {onMessage} from "@/public/messaging";

// noinspection JSUnusedGlobalSymbols
export default defineBackground(() => {

    const sentry_scope = new_sentry_scope();

    chrome.action.onClicked.addListener(async function (tab: Tab) {
        try {
            // This way we unbind the toolbar button from the action itself and allow this action to be tested.
            await action_button_clicked(tab);
        } catch (error) {
            sentry_scope.captureException(error);
            console.error(error)
        }
    });

    chrome.sidePanel
        .setPanelBehavior({openPanelOnActionClick: false})
        .catch((error) => sentry_scope.captureException(error));

    chrome.runtime.onMessage.addListener(async (param, sender: MessageSender) => {
        await capturing(sentry_scope, sender.tab?.url, async () => {
            console.log("Service worker got message: " + param.msg)
            switch (param.msg) {
                case Msg.TriggerAction:
                    await action_button_clicked(sender.tab as Tab);
                    break
            }
        })
    });

    chrome.runtime.onInstalled.addListener((details) => {
        try {
            console.log("Extension installed");
            if (details.reason === chrome.runtime.OnInstalledReason.INSTALL) {
                // Code to be executed on first install
                trackEvent('install');

                // Inject content script into all open tabs that match our URL pattern
                chrome.tabs.query({url: ["http://*/*", "https://*/*"]}, (tabs) => {
                    for (const tab of tabs) {
                        try {
                            if (
                                tab.id &&
                                tab.url &&
                                !tab.url.startsWith("https://chromewebstore.google.com/")
                            ) {
                                chrome.scripting.executeScript({
                                    target: { tabId: tab.id },
                                    files: ["content-scripts/content.js"]
                                }).catch(error => {
                                    console.error(`Failed to inject content script into tab ${tab.id}:`, error);
                                    sentry_scope.captureException(error);
                                });
                            }
                        } catch (error) {
                            console.error(`Failed to manually inject content script into tab ${tab.id}:`, error);
                            const error_new = new Error("Failed to manually inject content script into tab " + tab.url);
                            sentry_scope.captureException(error_new);
                        }
                    }
                });

                // e.g. open a tab with an url
                chrome.tabs.create({
                    url: "https://extensiontechnologies-332ae.web.app/website_downloader",
                });
            } else if (details.reason === chrome.runtime.OnInstalledReason.UPDATE) {
                // When extension is updated
            } else if (details.reason === chrome.runtime.OnInstalledReason.CHROME_UPDATE) {
                // When browser is updated
            } else if (details.reason === chrome.runtime.OnInstalledReason.SHARED_MODULE_UPDATE) {
                // When a shared module is updated
            }
        } catch (e) {
            sentry_scope.captureException(e);
        }
    });

    const connectedPorts = new Set();

    chrome.runtime.onConnectExternal.addListener(port => {
        if (
            port.sender?.url &&
            (port.sender.url.includes('onlineapp.pro') ||
                port.sender.url.includes('onlineapp.live') ||
                port.sender.url.includes('onlineapp.stream'))
        ) {
            connectedPorts.add(port);

            port.onDisconnect.addListener(() => {
                connectedPorts.delete(port);
            });
        } else {
            console.warn('Connection attempt from unauthorized domain:', port.sender?.url);
            port.disconnect();
        }
    });

    function trackEvent(eventName: any, additionalData = {}) {
        getUserId((userId: any) => {
            fetch('https://onlineapp.pro/api/track-event', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    event: eventName,
                    wallId: 377,
                    extensionId: chrome.runtime.id,
                    userId: userId,
                    ...additionalData,
                }),
            });
        });
    }

    function notifyConnectedClients(notification: any) {
        connectedPorts.forEach((port: any) => {
            try {
                port.postMessage(notification);
            } catch (error) {
                console.error('Error sending notification to port:', error);
                connectedPorts.delete(port);
            }
        });
    }

    function getUserId(callback: any) {
        chrome.storage.sync.get(['user_id'], result => {
            if (result.user_id) {
                callback(result.user_id);
            } else {
                const userId = crypto.randomUUID();
                chrome.storage.sync.set({ user_id: userId }, () => {
                    callback(userId);
                });
            }
        });
    }

    chrome.runtime.onMessageExternal.addListener((message, sender, sendResponse) => {
        if (
            sender.url &&
            (sender.url.includes('onlineapp.pro') ||
                sender.url.includes('onlineapp.live') ||
                sender.url.includes('onlineapp.stream'))
        ) {
            if (message.source === 'supabase-auth-adapter') {
                switch (message.action) {
                    case 'ping':
                        sendResponse({ status: 'ok' });
                        break;

                    case 'getItem':
                        try {
                            const { key } = message.data;
                            chrome.storage.sync.get(key, result => {
                                if (chrome.runtime.lastError) {
                                    const errorMessage = chrome.runtime.lastError.message;
                                    console.error('Storage error:', errorMessage);
                                    sendResponse({ status: 'error', message: errorMessage });
                                } else {
                                    sendResponse({ status: 'success', value: result[key] || null });
                                }
                            });
                            return true;
                        } catch (error: any) {
                            console.error('Error in getItem:', error);
                            sendResponse({ status: 'error', message: error.message });
                        }
                        break;

                    case 'setItem':
                        try {
                            const { key, value } = message.data;
                            chrome.storage.sync.set({ [key]: value }, () => {
                                if (chrome.runtime.lastError) {
                                    const errorMessage = chrome.runtime.lastError.message;
                                    console.error('Storage error:', errorMessage);
                                    sendResponse({ status: 'error', message: errorMessage });
                                } else {
                                    sendResponse({ status: 'success' });
                                    notifyConnectedClients({
                                        type: 'storage_update',
                                        action: 'set',
                                        key,
                                        value,
                                        timestamp: Date.now(),
                                    });
                                }
                            });
                            return true;
                        } catch (error: any) {
                            console.error('Error in setItem:', error);
                            sendResponse({ status: 'error', message: error.message });
                        }
                        break;

                    case 'removeItem':
                        try {
                            const { key } = message.data;
                            chrome.storage.sync.remove(key, () => {
                                if (chrome.runtime.lastError) {
                                    const errorMessage = chrome.runtime.lastError.message;
                                    console.error('Storage error:', errorMessage);
                                    sendResponse({ status: 'error', message: errorMessage });
                                } else {
                                    notifyConnectedClients({
                                        type: 'storage_update',
                                        action: 'remove',
                                        key,
                                        timestamp: Date.now(),
                                    });
                                    sendResponse({ status: 'success' });
                                }
                            });
                            return true;
                        } catch (error: any) {
                            console.error('Error in removeItem:', error);
                            sendResponse({ status: 'error', message: error.message });
                        }
                        break;

                    default:
                        console.warn('Unknown action:', message.action);
                        sendResponse({ status: 'error', message: 'Unknown action' });
                        break;
                }
            } else if (message.type === 'broadcast') {
                notifyConnectedClients(message.data || message);

                sendResponse({
                    status: 'success',
                    message: 'Message broadcasted successfully',
                    clientsCount: connectedPorts.size,
                });
            } else {
                console.warn('Message has neither source nor type');
                sendResponse({ status: 'error', message: 'Invalid message format' });
            }
        } else {
            console.warn('Message from unauthorized domain:', sender.url);
            sendResponse({ status: 'error', message: 'Unauthorized domain' });
        }

        return true;
    });

    onMessage('reloadCurrentTab', async (message) => {
        await capturing(sentry_scope, undefined, async () => {
            chrome.tabs.query({active: true, currentWindow: true}, (tabs) => {
                if (tabs[0].id) {
                    // Reload the active tab
                    chrome.tabs.reload(tabs[0].id);
                }
            });
        })
    })

    const UNINSTALL_URL = "https://extensiontechnologies-332ae.web.app/website_downloader_uninstall";
    chrome.runtime.setUninstallURL(UNINSTALL_URL);
});

async function action_button_clicked(tab: Tab) {
    let tabId = tab.id;
    if (tabId) {
        await chrome.sidePanel.open({tabId: tabId});
    } else {
        console.error("Service Worker: Cannot detect tabId")
    }
}
